mapper.select:
select ac.id, ac.name, ac.command, ac.role, ac.skill_id as skillId, ask.definition_desc as skillDesc, ad.id as agentId, ad.name as agentName, ac.create_time as createTime, ac.update_time as updateTime, ac.status, ac.remark from atomic_command ac left join agent_skill ask on ask.id = ac.skill_id left join agent_definition ad on ad.id = ask.agent_id
and (ac.name like concat('%', #{pageRequest.keyword}, '%') or ac.command like concat('%', #{pageRequest.keyword}, '%') or ac.role like concat('%', #{pageRequest.keyword}, '%') or ask.definition_desc like concat('%', #{pageRequest.keyword}, '%') or ad.name like concat('%', #{pageRequest.keyword}, '%'))
and ac.skill_id = #{pageRequest.skillId}
and ask.definition_desc like concat('%', #{pageRequest.skillDesc}, '%')
and ad.name like concat('%', #{pageRequest.agentName}, '%')
and ac.status = #{pageRequest.status}
order by ac.update_time desc nulls last, ac.create_time desc nulls last limit #{size} offset #{offset}

select count(1) from atomic_command ac left join agent_skill ask on ask.id = ac.skill_id left join agent_definition ad on ad.id = ask.agent_id
and (ac.name like concat('%', #{pageRequest.keyword}, '%') or ac.command like concat('%', #{pageRequest.keyword}, '%') or ac.role like concat('%', #{pageRequest.keyword}, '%') or ask.definition_desc like concat('%', #{pageRequest.keyword}, '%') or ad.name like concat('%', #{pageRequest.keyword}, '%'))
and ac.skill_id = #{pageRequest.skillId}
and ask.definition_desc like concat('%', #{pageRequest.skillDesc}, '%')
and ad.name like concat('%', #{pageRequest.agentName}, '%')
and ac.status = #{pageRequest.status}
